   2→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
   3→import { Circle, Group, Image as KonvaImage, Layer, Line, Rect, Shape, Stage, Text } from "react-konva";
   4→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
   5→import {
   6→    createFreedomWallItem,
   7→    deleteFreedomWallItem,
   8→    getCurrentFreedomWallWeek,
   9→    getFreedomWallItems,
  10→    updateFreedomWallItem
  11→} from "../../../../API/Api";
  12→import { useAuth } from "../../../Context/useAuth";
  13→import supabase from "../../../utils/supabaseClient";
  14→import "./freedomWall.css";
  15→
  16→const STAMP_ICONS = {
  17→    heart: "❤️",
  18→    star: "⭐",
  19→    fire: "🔥",
  20→    sparkles: "✨",
  21→    wow: "💥"
  22→};
  23→
  24→const STICKER_OPTIONS = {
  25→    dog: "🐶", cat: "🐱", bear: "🐻", unicorn: "🦄",
  26→    rocket: "🚀", rainbow: "🌈", sun: "🌞", moon: "🌙",
  27→    flower: "🌸", tree: "🌳", pizza: "🍕", guitar: "🎸"
  28→};
  29→
  30→const NOTE_FONT_OPTIONS = [
  31→    "Arial",
  32→    "Georgia",
  33→    "Courier New",
  34→    "Trebuchet MS",
  35→    "Times New Roman"
  36→];
  37→
  38→const NOTE_STYLE_OPTIONS = ["normal", "bold", "italic"];
  39→const WALL_MAX_WIDTH = 1080;
  40→const WALL_MIN_HEIGHT = 420;
  41→const WALL_MAX_HEIGHT = 900;
  42→const GRID_SIZE = 36;
  43→
  44→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  45→
  46→const snapToGrid = (px, gridSize = GRID_SIZE) => Math.round(px / gridSize) * gridSize;
  47→
  48→const sortItemsByZIndex = (items = []) => [...items].sort((a, b) => {
  49→    const zDiff = (a?.z_index || 0) - (b?.z_index || 0);
  50→    if(zDiff !== 0){
  51→        return zDiff;
  52→    }
  53→
  54→    const dateDiff = new Date(a?.created_at || 0) - new Date(b?.created_at || 0);
  55→    if(dateDiff !== 0){
  56→        return dateDiff;
  57→    }
  58→
  59→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  60→});
  61→
  62→const upsertById = (items = [], nextItem) => {
  63→    const existingIndex = items.findIndex((item) => String(item?.id) === String(nextItem?.id));
  64→    if(existingIndex === -1){
  65→        return [...items, nextItem];
  66→    }
  67→
  68→    const nextItems = [...items];
  69→    const previousItem = nextItems[existingIndex];
  70→    nextItems[existingIndex] = {
  71→        ...previousItem,
  72→        ...nextItem,
  73→        payload: {
  74→            ...(previousItem?.payload || {}),
  75→            ...(nextItem?.payload || {})
  76→        },
  77→        users: nextItem?.users || previousItem?.users || null
  78→    };
  79→    return nextItems;
  80→};
  81→
  82→const removeById = (items = [], itemId) => items.filter((item) => String(item?.id) !== String(itemId));
  83→
  84→const emojiCanvasCache = new Map();
  85→
  86→const useEmojiImage = (emoji, resolution = 128) => {
  87→    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);
  88→
  89→    useEffect(() => {
  90→        if(!emoji){
  91→            setImage(null);
  92→            return;
  93→        }
  94→
  95→        const cacheKey = `${emoji}-${resolution}`;
  96→        const cached = emojiCanvasCache.get(cacheKey);
  97→        if(cached){
  98→            setImage(cached);
  99→            return;
 100→        }
 101→
 102→        const canvas = document.createElement("canvas");
 103→        canvas.width = resolution;
 104→        canvas.height = resolution;
 105→        const ctx = canvas.getContext("2d");
 106→        ctx.clearRect(0, 0, resolution, resolution);
 107→        ctx.textAlign = "center";
 108→        ctx.textBaseline = "middle";
 109→        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
 110→        ctx.fillText(emoji, resolution / 2, resolution / 2);
 111→
 112→        const img = new window.Image();
 113→        img.onload = () => {
 114→            emojiCanvasCache.set(cacheKey, img);
 115→            setImage(img);
 116→        };
 117→        img.src = canvas.toDataURL();
 118→    }, [emoji, resolution]);
 119→
 120→    return image;
 121→};
 122→
 123→const StickerNode = ({item, stageWidth, stageHeight, isSelected, canEdit, onSelect, onDragEnd}) => {
 124→    const emoji = STICKER_OPTIONS[item?.payload?.sticker] || "🐶";
 125→    const image = useEmojiImage(emoji);
 126→    const scale = clamp(Number(item?.payload?.scale) || 1, 0.25, 6);
 127→    const size = clamp(64 * scale, 20, 420);
 128→    const x = clamp((Number(item?.payload?.x) || 0.5) * stageWidth, 0, Math.max(0, stageWidth - size));
 129→    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
 130→
 131→    if(!image){
 132→        return null;
 133→    }
 134→
 135→    return (
 136→        <>
 137→            <KonvaImage
 138→                x={x}
 139→                y={y}
 140→                width={size}
 141→                height={size}
 142→                image={image}
 143→                draggable={canEdit}
 144→                onClick={onSelect}
 145→                onTap={onSelect}
 146→                onDragEnd={onDragEnd}
 147→                rotation={Number(item?.payload?.rotation) || 0}
 148→            />
 149→            {isSelected && (
 150→                <Rect
 151→                    x={x}
 152→                    y={y}
 153→                    width={size}
 154→                    height={size}
 155→                    stroke="#4f46e5"
 156→                    strokeWidth={2}
 157→                    dash={[6, 4]}
 158→                    listening={false}
 159→                />
 160→            )}
 161→        </>
 162→    );
 163→};
 164→
 165→const StampNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected}) => {
 166→    const stamp = STAMP_ICONS[item?.payload?.stamp] || "✨";
 167→    const image = useEmojiImage(stamp, 64);
 168→    const scale = clamp(Number(item?.payload?.scale) || 1, 0.35, 5);
 169→    const size = clamp(34 * scale, 14, 220);
 170→    const x = clamp((Number(item?.payload?.x) || 0.5) * stageWidth, 0, Math.max(0, stageWidth - size));
 171→    const y = clamp((Number(item?.payload?.y) || 0.5) * stageHeight, 0, Math.max(0, stageHeight - size));
 172→
 173→    if(!image){
 174→        return null;
 175→    }
 176→
 177→    return (
 178→        <>
 179→            <KonvaImage
 180→                x={x}
 181→                y={y}
 182→                width={size}
 183→                height={size}
 184→                image={image}
 185→                draggable={canEdit}
 186→                onClick={onSelect}
 187→                onTap={onSelect}
 188→                onDragEnd={onDragEnd}
 189→                rotation={Number(item?.payload?.rotation) || 0}
 190→            />
 191→            {isSelected && (
 192→                <Rect
 193→                    x={x}
 194→                    y={y}
 195→                    width={size}
 196→                    height={size}
 197→                    stroke="#0f766e"
 198→                    strokeWidth={2}
 199→                    dash={[6, 4]}
 200→                    listening={false}
 201→                />
 202→            )}
 203→        </>
 204→    );
 205→};
