 207→const darkenColor = (hex, amount = 0.15) => {
 208→    const raw = hex?.replace("#", "") || "fff4a8";
 209→    const num = parseInt(raw.length === 3 ? raw.split("").map((c) => c + c).join("") : raw, 16);
 210→    const r = Math.max(0, Math.round(((num >> 16) & 255) * (1 - amount)));
 211→    const g = Math.max(0, Math.round(((num >> 8) & 255) * (1 - amount)));
 212→    const b = Math.max(0, Math.round((num & 255) * (1 - amount)));
 213→    return `rgb(${r},${g},${b})`;
 214→};
