 216→const NoteNode = ({item, stageWidth, stageHeight, canEdit, onSelect, onDragEnd, isSelected}) => {
 217→    const payload = item?.payload || {};
 218→    const width = clamp((Number(payload?.width) || 0.26) * stageWidth, 110, stageWidth * 0.9);
 219→    const height = clamp((Number(payload?.height) || 0.2) * stageHeight, 60, stageHeight * 0.8);
 220→    const x = clamp((Number(payload?.x) || 0.45) * stageWidth, 0, Math.max(0, stageWidth - width));
 221→    const y = clamp((Number(payload?.y) || 0.45) * stageHeight, 0, Math.max(0, stageHeight - height));
 222→    const fontStyle = NOTE_STYLE_OPTIONS.includes(payload?.fontStyle) ? payload.fontStyle : "normal";
 223→    const bgColor = payload?.bgColor || "#fff4a8";
 224→    const curlSize = Math.min(width, height) * 0.14;
 225→    const pinSize = Math.max(5, Math.min(width, height) * 0.04);
 226→
 227→    return (
 228→        <Group
 229→            x={x}
 230→            y={y}
 231→            draggable={canEdit}
 232→            onDragEnd={onDragEnd}
 233→            onClick={onSelect}
 234→            onTap={onSelect}
 235→            rotation={Number(payload?.rotation) || 0}
 236→        >
 237→            {/* Shadow layer beneath the note */}
 238→            <Shape
 239→                sceneFunc={(ctx, shape) => {
 240→                    ctx.beginPath();
 241→                    ctx.moveTo(2, 4);
 242→                    ctx.lineTo(width + 2, 2);
 243→                    ctx.lineTo(width - curlSize + 4, height + 3);
 244→                    ctx.lineTo(2, height + 2);
 245→                    ctx.closePath();
 246→                    ctx.fillStrokeShape(shape);
 247→                }}
 248→                fill="rgba(0,0,0,0.12)"
 249→                listening={false}
 250→            />
 251→
 252→            {/* Main note body */}
 253→            <Shape
 254→                sceneFunc={(ctx, shape) => {
 255→                    ctx.beginPath();
 256→                    ctx.moveTo(0, 0);
 257→                    ctx.lineTo(width, 0);
 258→                    ctx.lineTo(width, height - curlSize);
 259→                    ctx.lineTo(width - curlSize, height);
 260→                    ctx.lineTo(0, height);
 261→                    ctx.closePath();
 262→                    ctx.fillStrokeShape(shape);
 263→                }}
 264→                fill={bgColor}
 265→                stroke={isSelected ? "#a21caf" : "rgba(0,0,0,0.1)"}
 266→                strokeWidth={isSelected ? 2 : 0.5}
 267→            />
 268→
 269→            {/* Page curl triangle */}
 270→            <Shape
 271→                sceneFunc={(ctx, shape) => {
 272→                    ctx.beginPath();
 273→                    ctx.moveTo(width, height - curlSize);
 274→                    ctx.lineTo(width - curlSize, height - curlSize);
 275→                    ctx.lineTo(width - curlSize, height);
 276→                    ctx.closePath();
 277→                    ctx.fillStrokeShape(shape);
 278→                }}
 279→                fill={darkenColor(bgColor, 0.12)}
 280→                listening={false}
 281→            />
 282→
 283→            {/* Curl fold shadow */}
 284→            <Shape
 285→                sceneFunc={(ctx, shape) => {
 286→                    ctx.beginPath();
 287→                    ctx.moveTo(width - curlSize, height);
 288→                    ctx.lineTo(width, height - curlSize);
 289→                    ctx.lineTo(width - curlSize * 0.55, height - curlSize * 0.55);
 290→                    ctx.closePath();
 291→                    ctx.fillStrokeShape(shape);
 292→                }}
 293→                fill="rgba(0,0,0,0.06)"
 294→                listening={false}
 295→            />
 296→
 297→            {/* Text content */}
 298→            <Text
 299→                x={12}
 300→                y={pinSize * 2 + 10}
 301→                width={width - 24}
 302→                height={height - pinSize * 2 - curlSize - 16}
 303→                text={payload?.text || ""}
 304→                fontFamily={payload?.fontFamily || "Arial"}
 305→                fontStyle={fontStyle}
 306→                fontSize={clamp(Number(payload?.fontSize) || 16, 10, 64)}
 307→                fill={payload?.fontColor || "#1f2937"}
 308→                wrap="word"
 309→                lineHeight={1.3}
 310→            />
 311→
 312→            {/* Left push pin */}
 313→            <Circle x={width * 0.18} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
 314→            <Line points={[width * 0.18, pinSize * 2 + 2, width * 0.18, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
 315→
 316→            {/* Right push pin */}
 317→            <Circle x={width * 0.82} y={pinSize + 2} radius={pinSize} fill="#e63946" stroke="#b71c2a" strokeWidth={1} listening={false} />
 318→            <Line points={[width * 0.82, pinSize * 2 + 2, width * 0.82, pinSize * 2 + 6]} stroke="#999" strokeWidth={1.5} listening={false} />
 319→
 320→            {/* Pin highlights (glossy effect) */}
 321→            <Circle x={width * 0.18 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
 322→            <Circle x={width * 0.82 - pinSize * 0.25} y={pinSize * 0.7 + 2} radius={pinSize * 0.3} fill="rgba(255,255,255,0.45)" listening={false} />
 323→        </Group>
 324→    );
 325→};
