 327→const formatWeekLabel = (week = null) => {
 328→    if(!week?.week_start || !week?.week_end){
 329→        return "No active week";
 330→    }
 331→
 332→    const startDate = new Date(week.week_start);
 333→    const endDate = new Date(week.week_end);
 334→    return `${startDate.toLocaleDateString()} - ${endDate.toLocaleDateString()} (UTC)`;
 335→};
 336→
 337→const isCanvasBackgroundTarget = (target, stage) => {
 338→    if(!target || !stage){
 339→        return false;
 340→    }
 341→
 342→    if(target === stage){
 343→        return true;
 344→    }
 345→
 346→    return target.getParent?.() === stage;
 347→};
