 349→const FreedomWallPage = () => {
 350→    const {session, user, openAuthModal} = useAuth();
 351→    const queryClient = useQueryClient();
 352→    const shellRef = useRef(null);
 353→    const draftDoodleRef = useRef([]);
 354→    const [shellWidth, setShellWidth] = useState(980);
 355→    const [activeTool, setActiveTool] = useState("doodle");
 356→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 357→    const [doodleSize, setDoodleSize] = useState(3.2);
 358→    const [draftDoodlePoints, setDraftDoodlePoints] = useState([]);
 359→    const [isDrawing, setIsDrawing] = useState(false);
 360→    const [selectedSticker, setSelectedSticker] = useState("dog");
 361→    const [wallError, setWallError] = useState(null);
 362→    const [selectedStamp, setSelectedStamp] = useState("heart");
 363→    const [selectedItemId, setSelectedItemId] = useState(null);
 364→    const [noteModal, setNoteModal] = useState(null);
 365→    const [noteEditor, setNoteEditor] = useState({
 366→        text: "",
 367→        fontFamily: "Arial",
 368→        fontStyle: "normal",
 369→        fontColor: "#1f2937",
 370→        bgColor: "#fff4a8",
 371→        fontSize: 16
 372→    });
 373→
 374→    const authToken = session?.access_token || null;
 375→    const currentUser = user?.userData?.[0] || null;
 376→    const currentUserId = currentUser?.id || null;
 377→    const canWrite = Boolean(currentUserId);
 378→
 379→    const {
 380→        data: activeWeekData,
 381→        isLoading: isWeekLoading,
 382→        error: weekError
 383→    } = useQuery({
 384→        queryKey: ["freedomWallCurrentWeek"],
 385→        queryFn: () => getCurrentFreedomWallWeek(authToken),
 386→        refetchOnWindowFocus: true,
 387→        staleTime: 30 * 1000
 388→    });
 389→
 390→    const activeWeek = activeWeekData?.week || null;
 391→    const weekId = activeWeek?.id || null;
 392→
 393→    const itemsQueryKey = useMemo(() => ["freedomWallItems", weekId], [weekId]);
 394→
 395→    const {
 396→        data: itemsData,
 397→        isLoading: isItemsLoading
 398→    } = useQuery({
 399→        queryKey: itemsQueryKey,
 400→        queryFn: () => getFreedomWallItems(weekId, {limit: 400}, authToken),
 401→        enabled: Boolean(weekId),
 402→        refetchOnWindowFocus: false,
 403→        staleTime: 20 * 1000
 404→    });
 405→
 406→    useEffect(() => {
 407→        const updateShellWidth = () => {
 408→            const nextWidth = shellRef.current?.clientWidth || 980;
 409→            setShellWidth(nextWidth);
 410→        };
 411→
 412→        updateShellWidth();
 413→        window.addEventListener("resize", updateShellWidth);
 414→
 415→        let resizeObserver = null;
 416→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 417→            resizeObserver = new ResizeObserver(updateShellWidth);
 418→            resizeObserver.observe(shellRef.current);
 419→        }
 420→
 421→        return () => {
 422→            window.removeEventListener("resize", updateShellWidth);
 423→            if(resizeObserver){
 424→                resizeObserver.disconnect();
 425→            }
 426→        };
 427→    }, []);
 428→
 429→    const stageWidth = useMemo(() => clamp(shellWidth - 12, 280, WALL_MAX_WIDTH), [shellWidth]);
 430→    const stageHeight = useMemo(() => clamp(Math.round(stageWidth * 0.64), WALL_MIN_HEIGHT, WALL_MAX_HEIGHT), [stageWidth]);
 431→
 432→    const sortedItems = useMemo(() => sortItemsByZIndex(itemsData?.data || []), [itemsData?.data]);
 433→    const maxZIndex = useMemo(() => {
 434→        if(!sortedItems.length){
 435→            return 0;
 436→        }
 437→        return sortedItems.reduce((maxValue, item) => Math.max(maxValue, Number(item?.z_index) || 0), 0);
 438→    }, [sortedItems]);
 439→
 440→    const selectedItem = useMemo(() => {
 441→        if(!selectedItemId){
 442→            return null;
 443→        }
 444→        return sortedItems.find((item) => String(item?.id) === String(selectedItemId)) || null;
 445→    }, [selectedItemId, sortedItems]);
 446→
 447→    const selectedNote = useMemo(() => (
 448→        selectedItem?.item_type === "note" ? selectedItem : null
 449→    ), [selectedItem]);
 450→
 451→    const selectedItemCanEdit = Boolean(selectedItem && currentUserId && String(selectedItem.user_id) === String(currentUserId));
 452→
 453→    useEffect(() => {
 454→        if(!selectedNote){
 455→            return;
 456→        }
 457→
 458→        const payload = selectedNote.payload || {};
 459→        setNoteEditor({
 460→            text: payload.text || "",
 461→            fontFamily: payload.fontFamily || "Arial",
 462→            fontStyle: NOTE_STYLE_OPTIONS.includes(payload.fontStyle) ? payload.fontStyle : "normal",
 463→            fontColor: payload.fontColor || "#1f2937",
 464→            bgColor: payload.bgColor || "#fff4a8",
 465→            fontSize: clamp(Number(payload.fontSize) || 16, 10, 64)
 466→        });
 467→    }, [selectedNote]);
 468→
 469→    const setItemsCache = useCallback((updater) => {
 470→        if(!weekId){
 471→            return;
 472→        }
 473→
 474→        queryClient.setQueryData(itemsQueryKey, (old) => {
 475→            const previousItems = Array.isArray(old?.data) ? old.data : [];
 476→            const nextItems = sortItemsByZIndex(updater(previousItems));
 477→            return {
 478→                ...(old || {}),
 479→                data: nextItems,
 480→                hasMore: false,
 481→                nextCursor: null
 482→            };
 483→        });
 484→    }, [itemsQueryKey, queryClient, weekId]);
 485→
 486→    const createItemMutation = useMutation({
 487→        mutationFn: ({payload}) => createFreedomWallItem(authToken, payload),
 488→        onMutate: async({payload}) => {
 489→            const optimisticId = `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 490→            const optimisticItem = {
 491→                id: optimisticId,
 492→                week_id: payload.weekId,
 493→                user_id: currentUserId,
 494→                item_type: payload.itemType,
 495→                payload: payload.payload,
 496→                z_index: payload.zIndex || 0,
 497→                created_at: new Date().toISOString(),
 498→                updated_at: new Date().toISOString(),
 499→                deleted_at: null,
 500→                users: currentUser ? {
 501→                    id: currentUser.id,
 502→                    name: currentUser.name,
 503→                    image_url: currentUser.image_url,
 504→                    badge: currentUser.badge
 505→                } : null
 506→            };
 507→
 508→            setItemsCache((items) => [...items, optimisticItem]);
 509→            return {optimisticId: optimisticId};
 510→        },
 511→        onSuccess: (response, _variables, context) => {
 512→            const createdItem = response?.item;
 513→            if(!createdItem?.id){
 514→                return;
 515→            }
 516→
 517→            setItemsCache((items) => {
 518→                const withoutOptimistic = context?.optimisticId
 519→                    ? removeById(items, context.optimisticId)
 520→                    : items;
 521→                return upsertById(withoutOptimistic, createdItem);
 522→            });
 523→        },
 524→        onError: (error, variables, context) => {
 525→            console.error("Freedom Wall create error:", error, "variables:", variables);
 526→            if(context?.optimisticId){
 527→                setItemsCache((items) => removeById(items, context.optimisticId));
 528→            }
 529→            const message = error?.message || error?.error || "Failed to place item";
 530→            setWallError(message);
 531→            setTimeout(() => setWallError((prev) => prev === message ? null : prev), 4000);
 532→        }
 533→    });
 534→
 535→    const updateItemMutation = useMutation({
 536→        mutationFn: ({itemId, payload}) => updateFreedomWallItem(authToken, itemId, payload),
 537→        onMutate: async({itemId, payload}) => {
 538→            let previousItem = null;
 539→            setItemsCache((items) => {
 540→                previousItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 541→                if(!previousItem){
 542→                    return items;
 543→                }
 544→
 545→                return items.map((item) => {
 546→                    if(String(item?.id) !== String(itemId)){
 547→                        return item;
 548→                    }
 549→
 550→                    const mergedPayload = payload?.payload !== undefined
 551→                        ? {...(item?.payload || {}), ...(payload.payload || {})}
 552→                        : item?.payload;
 553→
 554→                    return {
 555→                        ...item,
 556→                        payload: mergedPayload,
 557→                        z_index: payload?.zIndex !== undefined ? payload.zIndex : item?.z_index
 558→                    };
 559→                });
 560→            });
 561→            return {previousItem: previousItem};
 562→        },
 563→        onSuccess: (response) => {
 564→            const updatedItem = response?.item;
 565→            if(!updatedItem?.id){
 566→                return;
 567→            }
 568→
 569→            setItemsCache((items) => upsertById(items, updatedItem));
 570→        },
 571→        onError: (_error, variables, context) => {
 572→            if(!context?.previousItem){
 573→                return;
 574→            }
 575→
 576→            setItemsCache((items) => upsertById(items, context.previousItem));
 577→            if(variables?.itemId){
 578→                setSelectedItemId(String(variables.itemId));
 579→            }
 580→        }
 581→    });
 582→
 583→    const deleteItemMutation = useMutation({
 584→        mutationFn: ({itemId}) => deleteFreedomWallItem(authToken, itemId),
 585→        onMutate: async({itemId}) => {
 586→            let removedItem = null;
 587→            setItemsCache((items) => {
 588→                removedItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 589→                return removeById(items, itemId);
 590→            });
 591→            return {removedItem: removedItem};
 592→        },
 593→        onError: (_error, _variables, context) => {
 594→            if(!context?.removedItem){
 595→                return;
 596→            }
 597→            setItemsCache((items) => upsertById(items, context.removedItem));
 598→        }
 599→    });
 600→
 601→    useEffect(() => {
 602→        if(!weekId){
 603→            return;
 604→        }
 605→
 606→        const channel = supabase
