1200→                                            lineCap="round"
1201→                                            lineJoin="round"
1202→                                            tension={0.12}
1203→                                            onClick={handleSelectItem}
1204→                                            onTap={handleSelectItem}
1205→                                        />
1206→                                    );
1207→                                }
1208→
1209→                                if(item?.item_type === "sticker"){
1210→                                    return (
1211→                                        <StickerNode
1212→                                            key={item.id}
1213→                                            item={item}
1214→                                            stageWidth={stageWidth}
1215→                                            stageHeight={stageHeight}
1216→                                            canEdit={canEditItem}
1217→                                            isSelected={isSelected}
1218→                                            onSelect={handleSelectItem}
1219→                                            onDragEnd={(event) => moveItemFromDrag(item, event)}
1220→                                        />
1221→                                    );
1222→                                }
1223→
1224→                                if(item?.item_type === "stamp"){
1225→                                    return (
1226→                                        <StampNode
1227→                                            key={item.id}
1228→                                            item={item}
1229→                                            stageWidth={stageWidth}
1230→                                            stageHeight={stageHeight}
1231→                                            canEdit={canEditItem}
1232→                                            isSelected={isSelected}
1233→                                            onSelect={handleSelectItem}
1234→                                            onDragEnd={(event) => moveItemFromDrag(item, event)}
1235→                                        />
1236→                                    );
1237→                                }
1238→
1239→                                if(item?.item_type === "note"){
1240→                                    return (
1241→                                        <NoteNode
1242→                                            key={item.id}
1243→                                            item={item}
1244→                                            stageWidth={stageWidth}
1245→                                            stageHeight={stageHeight}
1246→                                            canEdit={canEditItem}
1247→                                            isSelected={isSelected}
1248→                                            onSelect={handleSelectItem}
1249→                                            onDragEnd={(event) => moveItemFromDrag(item, event)}
1250→                                        />
1251→                                    );
1252→                                }
1253→
1254→                                return null;
1255→                            })}
1256→
1257→                            {isDrawing && draftDoodlePoints.length >= 4 && (
1258→                                <Line
1259→                                    points={draftDoodlePoints.map((point, pointIndex) => (
1260→                                        pointIndex % 2 === 0 ? point * stageWidth : point * stageHeight
1261→                                    ))}
1262→                                    stroke={doodleColor}
1263→                                    strokeWidth={doodleSize}
1264→                                    lineCap="round"
1265→                                    lineJoin="round"
1266→                                    tension={0.12}
1267→                                />
1268→                            )}
1269→                        </Layer>
1270→                    </Stage>
1271→                )}
1272→            </div>
1273→
1274→            {wallError && (
1275→                <div className="freedom-wall-error-toast">{wallError}</div>
1276→            )}
1277→
1278→            <div className="freedom-wall-footer">
1279→                <span>{sortedItems.length} items this week</span>
1280→                <span>
1281→                    {createItemMutation.isPending || updateItemMutation.isPending || deleteItemMutation.isPending
1282→                        ? "Syncing..."
1283→                        : "Synced"}
1284→                </span>
1285→            </div>
1286→        </div>
1287→    );
1288→};
